int calculateMaxProfit(int* prices, int n) {
    if(n<2) return 0;
    int hold = -prices[0];
    int notHold = 0;

    for (int i = 1; i < n; i++) {
        if (hold + prices[i] > notHold)
            notHold = hold + prices[i];

        if (-prices[i] > hold)
            hold = -prices[i];
    }

    return notHold;
}

code.Java:
static int calculateMaxProfit(int[] stockPrices) {

    int minPrice = Integer.MAX_VALUE;
    int maxProfit = 0;

    for (int price : stockPrices) {

        // Track minimum buying price
        minPrice = Math.min(minPrice, price);

        // Profit if sold today
        int profit = price - minPrice;

        // Track maximum profit
        maxProfit = Math.max(maxProfit, profit);
    }

    return maxProfit;
}

