function calculateMaxProfit(prices) {
    if(prices.length<2) return 0;
    let hold = -prices[0];
    let notHold = 0;

    for (let i = 1; i < prices.length; i++) {
        notHold = Math.max(notHold, hold + prices[i]);
        hold = Math.max(hold, -prices[i]);
    }

    return notHold;
}
